@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.RenderModeAttribute(typeof(NoInteractiveRenderMode))]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We value your privacy and are committed to protecting your personal data.
</p>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✔ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>What cookies we use</h2>
<ul>
    <li><strong>consent</strong> – Records whether you have accepted our cookie policy.</li>
</ul>

@code {
    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            HasConsented = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

